<?php namespace App\Domains\BeautyShop\Http\Controllers; use Illuminate\Http\Request; use App\Domains\BeautyShop\Models\BeautyProduct; class BeautyProductController { public function index() { return response()->json(BeautyProduct::all()); } public function store(Request $request) { $product = BeautyProduct::create($request->all()); return response()->json($product, 201); } public function show(BeautyProduct $product) { return response()->json($product); } public function update(Request $request, BeautyProduct $product) { $product->update($request->all()); return response()->json($product); } public function destroy(BeautyProduct $product) { $product->delete(); return response()->json(null, 204); } }
